import gzip,json,collections
p='/tmp/sglang_prof/1784441825.5502088/1784441825.551744-TP-0.trace.json.gz'
with gzip.open(p,'rt') as f: es=json.load(f)['traceEvents']
a=collections.defaultdict(float); n=collections.Counter()
for e in es:
 if e.get('cat')=='kernel' and e.get('ph')=='X':
  a[e['name']]+=e['dur']; n[e['name']]+=1
tot=sum(a.values())
print('events',sum(n.values()),'total_us',tot,'kernels',len(a))
for name,d in sorted(a.items(),key=lambda kv:kv[1],reverse=True)[:20]:
 print(f'{d/tot*100:.9f}% {d/1000:.6f} ms {n[name]} {name}')
PY","workdir":"/app","yield_time_ms":10000,"max_output_tokens":10000});
